{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표",
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표는 금요일 15:00 KST로 한다."
      },
      {
        "topic": "패키지명 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "topic": "릴리스 시점",
        "proposal": "수요일 릴리스",
        "status": "거절됨",
        "reason": "스모크 테스트 통과가 선행되어야 한다는 이의가 있었고 최종 결정은 금요일 15:00 KST였다."
      },
      {
        "topic": "스모크 스크립트 수정",
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경",
        "status": "거절됨",
        "reason": "합의 결과, 스크립트 우회보다 패키지 설정 우선 확인 원칙을 따르기로 했다."
      }
    ],
    "internal_stretch_goals": [
      {
        "topic": "내부 목표",
        "goal": "수요일을 내부 스트레치 목표로 고려할 수 있다."
      },
      {
        "topic": "README 검토",
        "goal": "README 설치 단계는 가능하면 목요일까지 검토한다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로",
        "impact": "릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래됨",
        "impact": "릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?"
      }
    ],
    "non_decisions": [
      {
        "topic": "고객/외부 파트너",
        "note": "고객 또는 외부 파트너는 명시되지 않았다."
      },
      {
        "topic": "보안/장애/법무/예산",
        "note": "보안 사고, 프로덕션 장애, 법무 승인, 예산 정보는 언급되지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "Friday 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 triage 노트를 작성한다.",
      "due": "Friday 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "no exact deadline",
      "status": "pending",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Unassigned",
      "task": "README 설치 단계를 목요일까지 검토한다.",
      "due": "Thursday if possible",
      "status": "pending",
      "source_certainty": "uncertain"
    }
  ],
  "followup_note": {
    "next_checks": [
      "스모크 테스트 결과가 금요일 10:00 KST 전에 공유되었는지 확인한다.",
      "tarball 경로가 올바른지 확인하고, 잘못된 경우 원인을 설정 또는 산출물 경로에서 먼저 찾는다.",
      "README 설치 단계가 최신인지 검토한다.",
      "최종 릴리스 승인자와 릴리스 노트에 내부 수요일 목표를 포함할지 여부를 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너명",
      "예산 정보",
      "보안 사고 또는 보안 승인",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "새로운 마감일",
      "새로운 소유자",
      "확정되지 않은 승인 권한"
    ]
  },
  "non_invention_rules": [
    "명시된 사실만 사용하고, 고객·예산·보안·장애·법무·소유자·마감일을 새로 만들지 않는다.",
    "수요일은 내부 스트레치 목표로만 기록하고, 공개 릴리스 목표로 바꾸지 않는다.",
    "tarball 경로 문제와 README 노후화는 위험으로만 기록하고 원인이나 해결책을 확장 추정하지 않는다.",
    "final release approval authority와 release note 문구는 미결 질문으로 유지한다.",
    "확정된 action item과 미배정 검토 항목을 구분한다."
  ]
}
